#[test]
fn metamod_annotated_error_for_missing_path() {
    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let input = MetamodInput {
        collection: "/testZone/home/irods".to_string(),
        data_object: Some("definitely_not_here_baton_rs_metamod".to_string()),
        operation: MetamodOperation::Add,
        avus: vec![Avu {
            attribute: "x".to_string(),
            value: "y".to_string(),
            units: None,
        }],
        error: None,
    };

    // metamod_one_annotated returns the input with an `error` field
    // populated, rather than propagating the iRODS error.
    let output = metamod_one_annotated(&mut conn, input);
    assert!(
        output.error.is_some(),
        "expected error annotation for missing path, got {:?}",
        output
    );
}

#[test]
fn metamod_empty_avus_is_no_op() {
    // metamod_one with an empty avus list shouldn't make any catalog
    // calls — verified by passing a deliberately bogus path that would
    // otherwise produce an iRODS error.
    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let input = MetamodInput {
        collection: "/testZone/home/irods".to_string(),
        data_object: Some("path_that_does_not_exist_but_irrelevant".to_string()),
        operation: MetamodOperation::Add,
        avus: vec![],
        error: None,
    };

    let output = metamod_one(&mut conn, input).expect("metamod_one with empty avus");
    assert_eq!(output.error, None);
    assert!(output.avus.is_empty());
}
